fn simd_operation(p1: &[f32; 4], p2: &[f32; 4]) -> [f32; 4] {
    unsafe {
        let p1_ = _mm_loadu_ps(p1.as_ptr());
        let p2_ = _mm_loadu_ps(p2.as_ptr());

        let b2: __m128 = _mm_dp_ps(p1_, p1_, 0b01110001);
        let s: __m128 = _mm_rsqrt_ps(b2);
        let bc: __m128 = _mm_dp_ps(p1_, p2_, 0b01110001);
        let t: __m128 = _mm_mul_ps(_mm_mul_ps(bc, _mm_rcp_ps(b2)), s);

        let mut result: [f32; 4] = std::mem::zeroed();
        _mm_storeu_ps(result.as_mut_ptr(), t);
        result
    }
}
