use std::time::Duration;

fn format_duration(seconds: u64) -> String {
    if seconds == 0 {
        return "now".to_string();
    }

    let mut remaining_seconds = seconds;
    let mut result = String::new();
    let units = [("year", 60 * 60 * 24 * 365), ("day", 60 * 60 * 24), ("hour", 60 * 60), ("minute", 60), ("second", 1)];

    for &(unit, duration) in &units {
        let count = remaining_seconds / duration;
        if count > 0 {
            result += if result.is_empty() { "" } else { if remaining_seconds % duration < 60 { " and " } else { ", " } };
            result += &format!("{} {}", count, if count > 1 { unit.to_string() + "s" } else { unit.to_string() });
            remaining_seconds %= duration;
        }
    }

    result
}
