public int minCostPath(int[][] grid) {
    int m = grid.length;
    int n = grid[0].length;

    // Initialize the cost grid with the same dimensions as the input grid
    int[][] cost = new int[m][n];

    // Fill the cost grid with the minimum cost to reach each cell
    cost[0][0] = grid[0][0];
    for (int i = 1; i < m; i++) {
        cost[i][0] = cost[i - 1][0] + grid[i][0];
    }
    for (int j = 1; j < n; j++) {
        cost[0][j] = cost[0][j - 1] + grid[0][j];
    }
    for (int i = 1; i < m; i++) {
        for (int j = 1; j < n; j++) {
            cost[i][j] = grid[i][j] + Math.min(cost[i - 1][j], cost[i][j - 1]);
        }
    }

    // Return the minimum cost to reach the bottom-right corner
    return cost[m - 1][n - 1];
}
