function parseImportExportStatement(statement) {
  const regex = /(?:import|export)\s*(?:{\s*([\w\s,]+)\s*}|[*])\s*from\s*'([^']+)';/;
  const match = statement.match(regex);
  if (match) {
    const [, exportsStr, module] = match;
    let exports = [];
    if (exportsStr) {
      exports = exportsStr.split(',').map(exportItem => exportItem.trim());
    } else {
      exports = ['*'];
    }
    return { module, exports };
  } else {
    throw new Error('Invalid import/export statement format');
  }
}

