function validateFormInput($input, $rules) {
    $errors = [];

    foreach ($rules as $field => $rule) {
        $rulesArray = explode('|', $rule);
        foreach ($rulesArray as $singleRule) {
            if ($singleRule === 'required' && empty($input[$field])) {
                $errors[$field][] = "The $field field is required.";
            } elseif ($singleRule === 'alpha' && !ctype_alpha($input[$field])) {
                $errors[$field][] = "The $field field must contain only alphabetic characters.";
            } elseif (strpos($singleRule, 'max:') === 0) {
                $maxLength = (int) substr($singleRule, 4);
                if (strlen($input[$field]) > $maxLength) {
                    $errors[$field][] = "The $field field must not exc

eed $maxLength characters in length.";
                }
            }
        }
    }

    return $errors;
}

