function minimizeTaskCompletionTime(tasks) {
  const taskMap = new Map();
  for (const task of tasks) {
    if (!taskMap.has(task.id)) {
      taskMap.set(task.id, []);
    }
    taskMap.get(task.id).push(task.duration);
  }

  let totalTime = 0;
  for (const durations of taskMap.values()) {
    durations.sort((a, b) => b - a);
    let timeTaken = 0;
    for (let i = 0; i < durations.length; i++) {
      timeTaken = Math.max(timeTaken, totalTime) + durations[i];
      totalTime = timeTaken;
    }
  }

  return totalTime;
}

