public class FileProcessor
{
    private readonly string _directoryPath;
    private readonly int _trials;
    private int _handled;
    private readonly Subject<string> _collection = new Subject<string>();
    private readonly AutoResetEvent _block = new AutoResetEvent(false);
    private readonly JsonSerializer _serializer = new JsonSerializer();

    public FileProcessor(string directoryPath, int trials)
    {
        _directoryPath = directoryPath;
        _trials = trials;
    }

    public void StartProcessing()
    {
        var watcher = new FileSystemWatcher(_directoryPath, "*.json");
        watcher.Created += OnFileCreated;

watcher.EnableRaisingEvents = true;
    }

    private void OnFileCreated(object sender, FileSystemEventArgs e)
    {
        var json = File.ReadAllText(e.FullPath);
        var message = _serializer.DeserializeFromString<string>(json);
        _collection.OnNext(message);
        _handled++;

        if (File.Exists(e.FullPath))
        {
            File.Delete(e.FullPath);
            if (_handled == _trials)
            {
                _block.Set();
            }
        }
    }

    public IObservable<string> GetProcessedMessages()
    {
        return _collection;
    }

    public void WaitForCompletion()
    {
        _block.WaitOne();
    }
}
