vector<int> convolution(vector<int> a, vector<int> b) {
    int n = a.size();
    vector<int> c(2 * n - 1, 0);
    for (int i = 0; i < 2 * n - 1; ++i) {
        for (int j = max(0, i - n + 1); j <= min(i, n - 1); ++j) {
