func calculateDistanceToTask(userLocation: CLLocation, taskLocation: CLLocation) -> CLLocationDistance {
    let lat1 = userLocation.coordinate.latitude.degreesToRadians
    let lon1 = userLocation.coordinate.longitude.degreesToRadians
    let lat2 = taskLocation.coordinate.latitude.degreesToRadians
    let lon2 = taskLocation.coordinate.longitude.degreesToRadians

    let dLat = lat2 - lat1
    let dLon = lon2 - lon1

    let a = sin(dLat / 2) * sin(dLat / 2) + sin(dLon / 2) * sin(dLon / 2) * cos(lat1) * cos(lat2)
    let c = 2 * atan2(sqrt(a), sqrt(1 - a))

    let radiusOfEarth = 6371000.0 // in meters
    let distance = radiusOfEarth * c

    return distance
}

extension Double {
    var degreesToRadians: Double { return self * .pi / 180 }
}
