function calculateAverageFromHTML(htmlSnippet, columnIndex) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlSnippet, 'text/html');
  const table = doc.querySelector('table');
  const rows = table.querySelectorAll('tr');

  let sum = 0;
  let count = 0;

  for (let i = 1; i < rows.length; i++) { // Start from index 1 to skip header row
    const cells = rows[i].querySelectorAll('td');
    if (cells.length > columnIndex) {
      const value = parseFloat(cells[columnIndex].textContent);
      if (!isNaN(value)) {
        sum += value;
        count++;
      }
    }
  }

  if (count === 0) {
    return 0;
  }

  const average = sum / count;
  return average.toFixed(2);
}
