class CircularQueue:
    def __init__(self, size):
        self.size = size
        self.queue = [None] * size
        self.cursor = -1

    def enqueue(self, element):
        self.cursor = (self.cursor + 1) % self.size
        self.queue[self.cursor] = element

    def dequeue(self):
        oldest_element = self.queue[(self.cursor + 1) % self.size]
        self.queue[(self.cursor + 1) % self.size] = None
        return oldest_element

    def next(self, increment=True):
        if increment:
            self.cursor = (self.cursor + 1) % self.size

    def get_cursor(self):
        return self.cursor
