public class FluidSimulation {
    public static int[][] simulateFluid(int[][] grid, int iterations) {
        int rows = grid.length;
        int cols = grid[0].length;
        int[][] result = new int[rows][cols];

        while (iterations > 0) {
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols; j++) {
                    int neighbors = 0;
                    int totalFluid = grid[i][j];
                    if (i > 0) {
                        neighbors++;
                        totalFluid += grid[i - 1][j] > 4 ? (grid[i - 1][j] - 4) / 4 : 0;
                    }
                    if (i < rows - 1) {
                        neighbors++;
                        totalFluid += grid[i + 1][j] > 4 ? (grid[i + 1

][j] - 4) / 4 : 0;
                    }
                    if (j > 0) {
                        neighbors++;
                        totalFluid += grid[i][j - 1] > 4 ? (grid[i][j - 1] - 4) / 4 : 0;
                    }
                    if (j < cols - 1) {
                        neighbors++;
                        totalFluid += grid[i][j + 1] > 4 ? (grid[i][j + 1] - 4) / 4 : 0;
                    }
                    result[i][j] = totalFluid + (grid[i][j] < 4 ? neighbors * ((grid[i][j] - 4) / 4) : 0);
                }
            }
            grid = result;
            iterations--;
        }
        return result;
    }
}
