        return 0 <= int(segment) <= 255 and (len(segment) == 1 or segment[0] != '0')

    def backtrack(start, parts):
        if parts == 4:
            return start == len(s)
        for i in range(1, 4):
            if start + i <= len(s):
                segment = s[start:start + i]
                if is_valid_segment(segment):
                    if backtrack(start + i, parts + 1):
                        return True
                else:
                    break
        return False

    return sum(backtrack(0, 1) for _ in range(4))
