function createDoubleStackMock<T>() {
  let items: T[] = [];

  return {
    hasSingleStack: () => items.length <= 1,
    hasSingleItem: () => items.length === 1,
    getTopItem: () => items[items.length - 1],
    popUntil: (condition: (item: T) => boolean) => {
      const poppedItems: T[] = [];
      while (items.length > 0 && !condition(items[items.length - 1])) {
        poppedItems.push(items.pop() as T);
      }
      return poppedItems;
    },
  };
}

