import numpy as np

class PoincareBall:
    def __init__(self, dimension):
        self.dimension = dimension

    def distance(self, x, y):
        if len(x) != self.dimension or len(y) != self.dimension:
            raise ValueError("Point dimensions do not match the Poincaré ball dimension")
        x = np.array(x)
        y = np.array(y)
        return np.arccosh(1 + 2 * np.sum((x - y) ** 2) / ((1 - np.sum(x ** 2)) * (1 - np.sum(y ** 2))))

    def mobius_addition(self, x, y):
        if len(x) != self.dimension or len(y) != self.dimension:
            raise ValueError("Point dimensions do not match the Poincaré ball dimension")
        x = np.array(x)
        y = np.array(y)
        numerator = (1 + 2 * np.dot(x, y) + np.sum(y ** 2)) * (1 - np

.sum(x ** 2))
        denominator = (1 + 2 * np.dot(x, y) + np.sum(x ** 2)) * (1 - np.sum(y ** 2))
        return ((1 + 2 * np.dot(x, y) + np.sum(x ** 2)) * y - (1 + 2 * np.dot(x, y) + np.sum(y ** 2)) * x) / (numerator / denominator)

    def inverse_mobius(self, x):
        if len(x) != self.dimension:
            raise ValueError("Point dimension does not match the Poincaré ball dimension")
        x = np.array(x)
        return x / (1 + np.sum(x ** 2) / 2)
