class EngineMonitor {
private:
    static constexpr unsigned num_cylinders = 6;
    std::deque<std::pair<std::chrono::steady_clock::time_point, unsigned>> speed_history;

public:
    EngineMonitor() {}

    void updateSpeed(unsigned speed) {
        speed_history.emplace_back(std::chrono::steady_clock::now(), speed);
    }

    unsigned averageSpeed(unsigned duration) {
        auto end_time = std::chrono::steady_clock::now();
        auto start_time = end_time - std::chrono::seconds(duration);

        unsigned total_speed = 0;
        unsigned num_samples = 0;

for (auto it = speed_history.rbegin(); it != speed_history.rend(); ++it) {
            if (it->first < start_time) {
                break;
            }
            total_speed += it->second;
            num_samples++;
        }

        return num_samples > 0 ? total_speed / num_samples : 0;
    }
};

int main() {
    EngineMonitor monitor;
    monitor.updateSpeed(3000); // Update engine speed to 3000 rpm
    monitor.updateSpeed(3500); // Update engine speed to 3500 rpm

    unsigned avg_speed = monitor.averageSpeed(60); // Calculate average speed over 60 seconds
    std::cout << "Average engine speed over 60 seconds: " << avg_speed << " rpm" << std::endl;

    return 0;
