    unescape_string(s, true, '\\', '\"', false);
    std::cout << s << std::endl;  // Output: \world\

    s = "\\";
    unescape_string(s, true, '\\', '\"', false);
    std::cout << s << std::endl;  // Output: \

    return 0;
}
