public class NumberProcessor {
    private List<Integer> numbers;

    public NumberProcessor(List<Integer> numbers) {
        this.numbers = new ArrayList<>(numbers);
    }

    public List<Integer> handle(List<String> commands) {
        for (String command : commands) {
            char operation = command.charAt(0);
            if (operation == 'A') {
                int value = Integer.parseInt(command.substring(2));
                add(value);
            } else if (operation == 'M') {
                int value = Integer.parseInt(command.substring(2));
                multiply(value);
            } else if (operation == 'R') {
                reverse();

} else if (operation == 'P') {
                printNumbers();
            }
        }
        return numbers;
    }

    private void add(int value) {
        for (int i = 0; i < numbers.size(); i++) {
            numbers.set(i, numbers.get(i) + value);
        }
    }

    private void multiply(int value) {
        for (int i = 0; i < numbers.size(); i++) {
            numbers.set(i, numbers.get(i) * value);
        }
    }

    private void reverse() {
        Collections.reverse(numbers);
    }

    private void printNumbers() {
        System.out.println(numbers);
    }
}
