from datetime import datetime, timedelta

def calculate_end_date(start_date, repeat_frequency, occurrences):
    start = datetime.strptime(start_date, "%Y-%m-%d")
    if repeat_frequency == "daily":
        end_date = start + timedelta(days=occurrences - 1)
    elif repeat_frequency == "weekly":
        end_date = start + timedelta(weeks=occurrences - 1)
    elif repeat_frequency == "monthly":
        end_date = start.replace(day=1) + timedelta(days=occurrences*30)
    return end_date.strftime("%Y-%m-%d")
