def minCoins(coins, target):
    # Initialize an array to store the minimum number of coins needed for each amount from 0 to target
    dp = [float('inf')] * (target + 1)
    dp[0] = 0  # Base case: 0 coins needed to make 0 amount

    # Iterate through each coin denomination
    for coin in coins:
        # Update the minimum number of coins needed for each amount from coin to target
        for amount in range(coin, target + 1):
            dp[amount] = min(dp[amount], dp[amount - coin] + 1)

    # If it is not possible to make up the target amount, return -1
    if dp[target] == float('inf'):
        return -1
    else:
        return dp[target]
