function format_logoff_time($seconds) : string {
    $hours = floor($seconds / 3600);
    $minutes = floor(($seconds % 3600) / 60);
    $seconds = $seconds % 60;

    $formatted_time = sprintf("%02d:%02d:%02d", $hours, $minutes, $seconds);

    if ($hours >= 12) {
        $formatted_time .= " PM";
        if ($hours > 12) {
            $hours -= 12;
        }
    } else {
        $formatted_time .= " AM";
        if ($hours == 0) {
            $hours = 12;
        }
    }

    $formatted_time = sprintf("%02d:%s", $hours, substr($formatted_time, 3));

