struct WriteQueue {
    bufs: Vec<Vec<u8>>,
}

struct WriteBuffer {
    queue: WriteQueue,
}

impl WriteBuffer {
    fn new() -> WriteBuffer {
        WriteBuffer {
            queue: WriteQueue { bufs: Vec::new() },
        }
    }

    fn flatten(&mut self) {
        let mut flattened: Vec<u8> = Vec::new();
        for buf in &self.queue.bufs {
            flattened.extend(buf);
        }
        self.queue.bufs.clear();
        self.queue.bufs.push(flattened);
    }
}

struct AsyncIo {
    io: Vec<u8>,
    write_buf: WriteBuffer,
}

impl AsyncIo {
    fn new_buf(io: Vec<u8>, capacity: usize) -> AsyncIo {
        AsyncIo {
            io,
            write_buf: WriteBuffer {
                queue: WriteQueue { bufs: Vec::with_capacity(capacity) },

},
        }
    }

    fn write(&mut self, data: Vec<u8>) {
        self.write_buf.queue.bufs.push(data);
    }

    fn flush(&mut self) {
        self.write_buf.flatten();
        for buf in &self.write_buf.queue.bufs {
            self.io.extend(buf);
        }
        self.write_buf.queue.bufs.clear();
    }
}
