public enum ThirdPartyDependency: Hashable, Equatable, Codable {
    /// A dependency that represents a pre-compiled .xcframework.
    case xcframework(path: AbsolutePath)

    // MARK: - Hashable

    public func hash(into hasher: inout Hasher) {
        switch self {
        case .xcframework(let path):
            hasher.combine("xcframework")
            hasher.combine(path)
        }
    }

    // MARK: - Equatable

    public static func == (lhs: ThirdPartyDependency, rhs: ThirdPartyDependency) -> Bool {
        switch (lhs, rhs) {
        case let (.xcframework(lhsPath), .xcframework(rhsPath)):
            return lhsPath == rhsPath
        }
    }
}

// MARK: - Codable

extension

ThirdPartyDependency {
    private enum Kind: String, Codable {
        case xcframework
    }
}
